/**
 * Unit tests for task-agent-advisor PreToolUse[Task] hook
 *
 * Covers the generic→specialist prompt-shape nudge (general-purpose tasks
 * with a clear domain get a "consider ork:X" context line) plus the
 * pre-existing synonym and casing suggestions.
 */

import { describe, test, expect } from 'vitest';
import type { HookInput } from '../../types.js';
import {
  taskAgentAdvisor,
  matchSpecialistDomain,
} from '../../pretool/task/task-agent-advisor.js';

function makeInput(toolInput: Record<string, unknown>): HookInput {
  return {
    tool_name: 'Task',
    session_id: 'session-advisor',
    tool_input: toolInput,
  };
}

function contextOf(result: ReturnType<typeof taskAgentAdvisor>): string {
  return (result.hookSpecificOutput?.additionalContext as string) || '';
}

describe('matchSpecialistDomain', () => {
  test.each([
    ['investigate the failure in the deploy job and find the root cause', 'ork:debug-investigator'],
    ['run a security audit on the upload endpoint', 'ork:security-auditor'],
    ['write unit tests for the parser module', 'ork:test-generator'],
    ['review this PR for issues', 'ork:code-quality-reviewer'],
    ['create an alembic schema migration for the orders table', 'ork:database-engineer'],
    ['fix the GitHub Actions ci pipeline', 'ork:ci-cd-engineer'],
    ['do web research on competitor pricing', 'ork:web-research-analyst'],
    ['build a React component for the settings page', 'ork:frontend-ui-developer'],
    ['design the REST API endpoints for billing', 'ork:backend-system-architect'],
  ])('%s → %s', (text, expected) => {
    expect(matchSpecialistDomain(text, '')).toBe(expected);
  });

  test('matches in prompt when description is generic', () => {
    expect(
      matchSpecialistDomain('research task', 'Please write unit tests for src/auth.ts'),
    ).toBe('ork:test-generator');
  });

  test('returns null for genuinely mixed/generic tasks', () => {
    expect(matchSpecialistDomain('coordinate the milestone cleanup', 'List open issues and summarize')).toBeNull();
  });
});

describe('taskAgentAdvisor general-purpose nudge', () => {
  test('nudges specialist for domain-shaped general-purpose task', () => {
    const result = taskAgentAdvisor(
      makeInput({
        subagent_type: 'general-purpose',
        description: 'Investigate the failure in CI and find the root cause',
      }),
    );

    expect(result.continue).toBe(true);
    expect(contextOf(result)).toContain('ork:debug-investigator');
    expect(contextOf(result)).toContain('general-purpose');
  });

  test('stays silent for general-purpose without a domain match', () => {
    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'general-purpose', description: 'summarize the meeting notes' }),
    );

    expect(result.continue).toBe(true);
    expect(contextOf(result)).toBe('');
  });

  test('never blocks (advisory only)', () => {
    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'general-purpose', description: 'security audit of everything' }),
    );
    expect(result.continue).toBe(true);
  });

  test('other builtins (Explore) remain silent even with domain text', () => {
    const result = taskAgentAdvisor(
      makeInput({ subagent_type: 'Explore', description: 'write unit tests for x' }),
    );
    expect(contextOf(result)).toBe('');
  });
});

describe('pre-existing advisor behaviors still intact', () => {
  test('synonym suggestion for ad-hoc names', () => {
    const result = taskAgentAdvisor(makeInput({ subagent_type: 'code-reviewer', description: 'x' }));
    expect(contextOf(result)).toContain('ork:code-quality-reviewer');
  });

  test('casing fix for builtins', () => {
    const result = taskAgentAdvisor(makeInput({ subagent_type: 'explore', description: 'x' }));
    expect(contextOf(result)).toContain('Explore');
  });

  test('unknown custom types stay silent', () => {
    const result = taskAgentAdvisor(makeInput({ subagent_type: 'my-custom-agent', description: 'x' }));
    expect(contextOf(result)).toBe('');
  });
});
